// promptAudit.mjs — Run with: node promptAudit.mjs
// No external dependencies.

function auditSystemPrompt(prompt) {
  const findings = [];

  // 1. Vague role
  if (/\b(helpful|friendly)\s+assistant\b/i.test(prompt) &&
      !/\byou are a [a-z]+ (agent|system|bot|analyst)\b/i.test(prompt)) {
    findings.push({
      severity: "critical",
      code: "VAGUE_ROLE",
      message: "Prompt uses a generic persona without an operational role.",
      fix: 'Replace "helpful assistant" with a specific role, e.g. "You are a billing dispute agent..."',
    });
  }

  // 2. No output contract
  if (!/\b(output|return|respond with|format|schema|json|xml)\b/i.test(prompt)) {
    findings.push({
      severity: "critical",
      code: "NO_OUTPUT_CONTRACT",
      message: "No output format or schema specified.",
      fix: 'Add: "Output: JSON with keys action (str), reason (str), confidence (float 0-1)."',
    });
  }

  // 3. No stop condition
  if (!/\b(stop when|stop after|done|do not continue)\b/i.test(prompt)) {
    findings.push({
      severity: "critical",
      code: "NO_STOP_CONDITION",
      message: "No explicit stop condition for the agentic loop.",
      fix: 'Add: "Stop when: you have emitted the final result. Do not continue after that."',
    });
  }

  // 4. Injection risk
  if (/\{\{?user(|_input|_message)\}?\}/i.test(prompt) &&
      !/<[A-Z_]{3,}>/.test(prompt)) {
    findings.push({
      severity: "critical",
      code: "NO_INJECTION_GUARD",
      message: "User input is interpolated without structural delimiters.",
      fix: 'Wrap: "<USER_INPUT>\\n{user_input}\\n</USER_INPUT>"',
    });
  }

  return findings;
}

// ── Demo ──────────────────────────────────────────────────────────────────────
const badPrompt = `You are a helpful assistant. Answer the question: {user_input}`;
const findings = auditSystemPrompt(badPrompt);

if (findings.length === 0) {
  console.log("No issues found.");
} else {
  findings.forEach(({ severity, code, message, fix }) => {
    console.log(`[${severity.toUpperCase()}] ${code}`);
    console.log(`  Issue: ${message}`);
    console.log(`  Fix:   ${fix}\n`);
  });
}
// [CRITICAL] VAGUE_ROLE
//   Issue: Prompt uses a generic persona without an operational role.
//   Fix: Replace "helpful assistant" ...
//
// [CRITICAL] NO_OUTPUT_CONTRACT
// [CRITICAL] NO_STOP_CONDITION
// [CRITICAL] NO_INJECTION_GUARD
